141→    val minutesOfHour = UnsignedFieldSpec(
142→        PropertyAccessor(UtcOffsetFieldContainer::minutesOfHour),
143→        defaultValue = 0,
144→        minValue = 0,
145→        maxValue = 59,
146→        sign = sign,
147→    )
148→    val secondsOfMinute = UnsignedFieldSpec(
149→        PropertyAccessor(UtcOffsetFieldContainer::secondsOfMinute),
150→        defaultValue = 0,
