197→        spacePadding = padding.spaces(2)
198→    ) {
199→
200→    override val builderRepresentation: String
201→        get() =
202→            "${DateTimeFormatBuilder.WithUtcOffset::offsetHours.name}(${padding.toKotlinCode()})"
203→
204→    override fun equals(other: Any?): Boolean = other is UtcOffsetWholeHoursDirective && padding == other.padding
205→    override fun hashCode(): Int = padding.hashCode()
206→}
