26→internal class ConditionalFormatter<in T>(
27→    private val formatters: List<Pair<T.() -> Boolean, FormatterStructure<T>>>
28→): FormatterStructure<T> {
29→    override fun format(obj: T, builder: Appendable, minusNotRequired: Boolean) {
30→        for ((condition, formatter) in formatters) {
31→            if (obj.condition()) {
32→                formatter.format(obj, builder, minusNotRequired)
33→                return
34→            }
35→        }
36→    }
37→}
